import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as i,e as r}from"./app-0014a839.js";const h={},d=r('<h1 id="基本概念" tabindex="-1"><a class="header-anchor" href="#基本概念" aria-hidden="true">#</a> 基本概念</h1><p>查找是在大量的信息中寻找一个特定的信息元素，在计算机应用中，查找是常用的基本运算，例如编译程序中符号表的查找</p><h2 id="查找" tabindex="-1"><a class="header-anchor" href="#查找" aria-hidden="true">#</a> 查找</h2><p>在数据集合中寻找满足某种条件的数据元素的过程就是查找，查找的结果有两种：</p><ul><li>查找成功，找到目标</li><li>查找失败，没有找到目标</li></ul><h2 id="查找表" tabindex="-1"><a class="header-anchor" href="#查找表" aria-hidden="true">#</a> 查找表</h2><p>查找表也可以称为查找结构，用于查找的数据集合就是查找表。由同一类型的数据元素（记录组成），常见的就是数组、链表等数据结构.</p><p>对查找表可以做的操作有：</p><ul><li>查询某个特定元素是否在查找表中</li><li>检索满足条件的某特特定元素的数据元素的各种属性</li><li>在查找表中插入数据元素</li><li>从查找表中删除某个数据元素</li></ul><h2 id="静态查找表" tabindex="-1"><a class="header-anchor" href="#静态查找表" aria-hidden="true">#</a> 静态查找表</h2><h2 id="关键字" tabindex="-1"><a class="header-anchor" href="#关键字" aria-hidden="true">#</a> 关键字</h2><h2 id="平均查找长度" tabindex="-1"><a class="header-anchor" href="#平均查找长度" aria-hidden="true">#</a> 平均查找长度</h2>',12),t=[d];function n(c,l){return a(),i("div",null,t)}const _=e(h,[["render",n],["__file","base-concept.html.vue"]]);export{_ as default};
